import React from "react";

const AboutMe = () => {
    return(
        <ScrollAnimation
            animateIn='fadeIn'
            animateOut='fadeOut'>
            <h1 className="ui header" style={{fontWeight:"900"}}>About Me</h1>

        </ScrollAnimation>

    )
};
export default AboutMe;
